// SECURITY: Only these columns can be filtered/sorted on.
// This prevents attackers from referencing arbitrary columns or injecting SQL.
const ALLOWED_USER_COLUMNS: ReadonlySet<string> = new Set([
  'id',
  'username',
  'email',
  'full_name',
  'role',
  'status',
  'department',
  'created_at',
  'updated_at',
  'last_login',
]);

// SECURITY: Only these operators are permitted.
const ALLOWED_OPERATORS: ReadonlyMap<string, string> = new Map([
  ['eq', '='],
  ['neq', '!='],
  ['gt', '>'],
  ['gte', '>='],
  ['lt', '<'],
  ['lte', '<='],
  ['like', 'ILIKE'],
  ['not_like', 'NOT ILIKE'],
  ['in', 'IN'],
  ['not_in', 'NOT IN'],
  ['is_null', 'IS NULL'],
  ['is_not_null', 'IS NOT NULL'],
  ['between', 'BETWEEN'],
]);

const ALLOWED_SORT_ORDERS: ReadonlySet<string> = new Set(['ASC', 'DESC']);

// Free-text searchable columns
const FREE_TEXT_SEARCH_COLUMNS: readonly string[] = [
  'username',
  'email',
  'full_name',
  'department',
];

class SafeQueryBuilder {
  private conditions: string[] = [];
  private params: (string | number | boolean)[] = [];
  private paramIndex: number = 1;

  /**
   * Validates that a column name is in the whitelist.
   * This is the PRIMARY defense against SQL injection for column names,
   * which cannot be parameterized in PostgreSQL.
   */
  private validateColumn(column: string): string {
    const normalized = column.toLowerCase().trim();
    if (!ALLOWED_USER_COLUMNS.has(normalized)) {
      throw new InvalidFilterError(
        `Column "${column}" is not allowed for filtering. ` +
        `Allowed columns: ${[...ALLOWED_USER_COLUMNS].join(', ')}`
      );
    }
    // Return the identifier double-quoted to prevent any edge cases
    return `"${normalized}"`;
  }

  private validateOperator(operator: string): string {
    const normalized = operator.toLowerCase().trim();
    const sqlOp = ALLOWED_OPERATORS.get(normalized);
    if (!sqlOp) {
      throw new InvalidFilterError(
        `Operator "${operator}" is not allowed. ` +
        `Allowed operators: ${[...ALLOWED_OPERATORS.keys()].join(', ')}`
      );
    }
    return sqlOp;
  }

  addFilter(filter: SearchFilter): this {
    const safeColumn = this.validateColumn(filter.field);
    const sqlOperator = this.validateOperator(filter.operator);
    const op = filter.operator.toLowerCase().trim();

    if (op === 'is_null' || op === 'is_not_null') {
      // No value needed
      this.conditions.push(`${safeColumn} ${sqlOperator}`);
    } else if (op === 'in' || op === 'not_in') {
      const values = Array.isArray(filter.value) ? filter.value : [filter.value];
      if (values.length === 0) {
        throw new InvalidFilterError('IN/NOT IN operator requires at least one value');
      }
      const placeholders = values.map((v) => {
        this.params.push(v as string | number);
        return `$${this.paramIndex++}`;
      });
      this.conditions.push(`${safeColumn} ${sqlOperator} (${placeholders.join(', ')})`);
    } else if (op === 'between') {
      const values = Array.isArray(filter.value) ? filter.value : [];
      if (values.length !== 2) {
        throw new InvalidFilterError('BETWEEN operator requires exactly two values');
      }
      const p1 = `$${this.paramIndex++}`;
      const p2 = `$${this.paramIndex++}`;
      this.params.push(values[0] as string | number);
      this.params.push(values[1] as string | number);
      this.conditions.push(`${safeColumn} BETWEEN ${p1} AND ${p2}`);
    } else if (op === 'like' || op === 'not_like') {
      // Wrap value with % for partial matching, escape existing wildcards in user input
      const escaped = String(filter.value).replace(/%/g, '\\%').replace(/_/g, '\\_');
      this.params.push(`%${escaped}%`);
      this.conditions.push(`${safeColumn} ${sqlOperator} $${this.paramIndex++}`);
    } else {
      // Standard comparison: eq, neq, gt, gte, lt, lte
      this.params.push(filter.value as string | number | boolean);
      this.conditions.push(`${safeColumn} ${sqlOperator} $${this.paramIndex++}`);
    }

    return this;
  }

  addFreeTextSearch(searchTerm: string): this {
    if (!searchTerm || searchTerm.trim().length === 0) return this;

    const escaped = searchTerm.replace(/%/g, '\\%').replace(/_/g, '\\_');
    const likeClauses = FREE_TEXT_SEARCH_COLUMNS.map((col) => {
      // These columns are hardcoded, so they're safe — but we still quote them
      this.params.push(`%${escaped}%`);
      return `"${col}" ILIKE $${this.paramIndex++}`;
    });

    this.conditions.push(`(${likeClauses.join(' OR ')})`);
    return this;
  }

  buildWhereClause(): { whereClause: string; params: (string | number | boolean)[] } {
    if (this.conditions.length === 0) {
      return { whereClause: '', params: [] };
    }
    return {
      whereClause: `WHERE ${this.conditions.join(' AND ')}`,
      params: [...this.params],
    };
  }

  getNextParamIndex(): number {
    return this.paramIndex;
  }

  getParams(): (string | number | boolean)[] {
    return [...this.params];
  }
}

