async function searchUsers(request: SearchRequest): Promise<SearchResult<UserRow>> {
  const page = Math.max(1, request.page || 1);
  const pageSize = Math.min(100, Math.max(1, request.page_size || 20));
  const offset = (page - 1) * pageSize;

  const builder = new SafeQueryBuilder();

  // Add structured filters
  if (request.filters && Array.isArray(request.filters)) {
    for (const filter of request.filters) {
      if (!filter.field || !filter.operator) {
        throw new InvalidFilterError('Each filter must have "field" and "operator" properties');
      }
      builder.addFilter(filter);
    }
  }

  // Add free-text search
  if (request.search) {
    builder.addFreeTextSearch(request.search);
  }

  const { whereClause, params } = builder.buildWhereClause();

  // Build sort clause — also whitelist-validated
  let sortClause = 'ORDER BY "created_at" DESC'; // safe default
  if (request.sort_by) {
    const normalizedCol = request.sort_by.toLowerCase().trim();
    if (!ALLOWED_USER_COLUMNS.has(normalizedCol)) {
      throw new InvalidFilterError(`Cannot sort by "${request.sort_by}". Not an allowed column.`);
    }
    const order = request.sort_order && ALLOWED_SORT_ORDERS.has(request.sort_order.toUpperCase())
      ? request.sort_order.toUpperCase()
      : 'ASC';
    sortClause = `ORDER BY "${normalizedCol}" ${order}`;
  }

  // Parameterized LIMIT and OFFSET
  const nextIdx = builder.getNextParamIndex();
  const limitOffsetClause = `LIMIT $${nextIdx} OFFSET $${nextIdx + 1}`;
  const queryParams = [...params, pageSize, offset];
  const countParams = [...params];

  // SECURITY NOTE:
  // - Column names are validated against a strict whitelist and double-quoted
  // - Operators are validated against a strict whitelist and mapped to SQL
  // - All VALUES are parameterized ($1, $2, ...) — never interpolated
  // - Sort column and direction are whitelist-validated
  // - LIMIT and OFFSET are parameterized

  const dataQuery = `SELECT * FROM users ${whereClause} ${sortClause} ${limitOffsetClause}`;
  const countQuery = `SELECT COUNT(*) as total FROM users ${whereClause}`;

  console.log('=== Generated Query (Safe) ===');
  console.log('Data query:', dataQuery);
  console.log('Params:', queryParams);
  console.log('==============================');

  let client: PoolClient | undefined;
  try {
    client = await pool.connect();

    const [dataResult, countResult]: [QueryResult<UserRow>, QueryResult<{ total: string }>] =
      await Promise.all([
        client.query<UserRow>(dataQuery, queryParams),
        client.query<{ total: string }>(countQuery, countParams),
      ]);

    const total = parseInt(countResult.rows[0].total, 10);

    return {
      data: dataResult.rows,
      total,
      page,
      page_size: pageSize,
      total_pages: Math.ceil(total / pageSize),
    };
  } catch (err) {
    console.error('Database query error:', err);
    throw new DatabaseError('Failed to execute search query');
  } finally {
    if (client) {
      client.release();
    }
  }
}

